import type { Ref } from "react";
import { cn } from "../../lib/utils";
import { CalendarLegendItemType } from "../../types/calendar";
import { CalendarLegendProps } from "../../types/calendar-legend";
import { CalendarLegendItem } from "./CalendarLegendItem";

// Default legend item labels (would be localized in a real app)
const getDefaultLegendItemText = (type: CalendarLegendItemType, _locale?: string): string => {
  // In a real implementation, these would use i18n
  const labels: Record<string, string> = {
    [CalendarLegendItemType.Today]: "Today",
    [CalendarLegendItemType.Selected]: "Selected Day",
    [CalendarLegendItemType.Working]: "Working Day",
    [CalendarLegendItemType.NonWorking]: "Non-Working Day",
  };

  return labels[type] || type;
};

/**
 * CalendarLegend - Displays a legend for calendar special dates
 *
 * Shows color-coded legend items that correspond to special date types in the calendar.
 * Includes default items (Today, Selected Day, Working Day, Non-Working Day) and
 * supports custom items.
 */
export function CalendarLegend({
      hideToday = false,
      hideSelectedDay = false,
      hideNonWorkingDay = false,
      hideWorkingDay = false,
      items = [],
      onLegendItemSelect,
      locale,
      className,
      ref,
    }: CalendarLegendProps & { ref?: Ref<HTMLDivElement> }) {
    // Default legend items
    const defaultItems = [
      {
        type: CalendarLegendItemType.Today,
        text: getDefaultLegendItemText(CalendarLegendItemType.Today, locale),
        hidden: hideToday,
      },
      {
        type: CalendarLegendItemType.Selected,
        text: getDefaultLegendItemText(CalendarLegendItemType.Selected, locale),
        hidden: hideSelectedDay,
      },
      {
        type: CalendarLegendItemType.Working,
        text: getDefaultLegendItemText(CalendarLegendItemType.Working, locale),
        hidden: hideWorkingDay,
      },
      {
        type: CalendarLegendItemType.NonWorking,
        text: getDefaultLegendItemText(CalendarLegendItemType.NonWorking, locale),
        hidden: hideNonWorkingDay,
      },
    ].filter((item) => !item.hidden);

    // Combine default and custom items
    const allItems = [...defaultItems, ...items];

    if (allItems.length === 0) {
      return null;
    }

    return (
      <div
        ref={ref}
        role="list"
        aria-label="Calendar legend"
        className={cn(
          "p-3 bg-sapphire-card-bg border-t border-sapphire-border",
          "columns-2 sm:columns-3 gap-2",
          "w-full",
          className
        )}
      >
        {allItems.map((item, index) => (
          <CalendarLegendItem
            key={`${item.type}-${index}`}
            type={item.type}
            text={item.text}
            onClick={onLegendItemSelect ? () => onLegendItemSelect({ type: item.type, text: item.text }) : undefined}
          />
        ))}
      </div>
    );
  }
